import{Functions,Log as TcHmiLog}from"Beckhoff.TwinCAT.HMI.Framework/index.esm.js";export function Log(level,message,...optionalParameters){switch(level){case"Error":TcHmiLog.errorEx(message,...optionalParameters);break;case"Warning":TcHmiLog.warnEx(message,...optionalParameters);break;case"Info":TcHmiLog.infoEx(message,...optionalParameters);break;default:TcHmiLog.debugEx(message,...optionalParameters)}}Functions.registerFunctionEx("Log","TcHmi.Functions.Beckhoff",Log,{injectInGlobalObject:!0});